		return
	}

	log.Println("开始执行策略执行任务...")

	tradeDate := time.Now()

	// 从数据库获取所有启用的策略
	strategies, err := s.strategyRepo.GetEnabledStrategies()
	if err != nil {
		log.Printf("获取策略列表失败: %v", err)
		return
	}

	if len(strategies) == 0 {
		log.Println("没有启用的策略，跳过执行")
