			errorCount++
		} else {
			log.Printf("策略 %s 执行成功", strategy.StrategyID)
			successCount++
		}
	}

	log.Printf("策略执行任务完成，成功: %d，失败: %d", successCount, errorCount)
}

// isWeekend 判断是否为周末
func isWeekend(t time.Time) bool {
