<script setup>
import { ref, reactive, computed } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'

// 策略数据（长线）
const strategies = ref([
  {
    id: 'long_term_1',
    name: '高股息价值',
    description: '连续5年分红，股息率>5%，股价稳定，适合长期持有',
    successRate: 85.2,
    avgProfit: 28.5,
    parameters: [
      { key: 'dividendYield', label: '股息率%', type: 'number', min: 3, max: 10, step: 0.5, value: 5 },
      { key: 'dividendYears', label: '连续分红年', type: 'number', min: 3, max: 10, step: 1, value: 5 },
      { key: 'peRatio', label: 'PE上限', type: 'number', min: 5, max: 20, step: 1, value: 12 }
    ]
  },
  {
    id: 'long_term_2',
    name: '护城河龙头',
    description: '行业龙头，市场份额高，ROE>20%，护城河宽广',
    successRate: 82.1,
    avgProfit: 32.3,
    parameters: [
      { key: 'roeThreshold', label: 'ROE门槛%', type: 'number', min: 15, max: 30, step: 1, value: 20 },
      { key: 'marketShare', label: '市占率%', type: 'number', min: 10, max: 50, step: 5, value: 20 },
      { key: 'moatScore', label: '护城河评分', type: 'select', options: [{ value: 3, label: '强' }, { value: 2, label: '中等' }], value: 3 }
    ]
  },
  {
    id: 'long_term_3',
    name: '成长确定性',
    description: '未来3年业绩确定性增长，管理层优秀，现金流充裕',
    successRate: 78.6,
    avgProfit: 35.8,
    parameters: [
      { key: 'revenueCAGR', label: '营收CAGR%', type: 'number', min: 10, max: 40, step: 1, value: 20 },
      { key: 'debtRatio', label: '负债率上限%', type: 'number', min: 30, max: 70, step: 5, value: 50 },
      { key: 'fcfPositive', label: '连续正现金流年', type: 'number', min: 3, max: 10, step: 1, value: 5 }
    ]
  }
])

const selectedStrategy = ref('')
const strategyParameters = reactive({})
const strategyResults = ref([])
const loading = ref(false)

const avgScore = computed(() => {
  if (strategyResults.value.length === 0) return 0
  const sum = strategyResults.value.reduce((acc, result) => acc + result.score, 0)
  return sum / strategyResults.value.length
})

const highScoreSignals = computed(() => strategyResults.value.filter(result => result.score >= 0.8).length)

const expectedReturn = computed(() => {
  if (strategyResults.value.length === 0) return 0
  const returns = strategyResults.value.map(result => (result.takeProfitPrice - result.buyPrice) / result.buyPrice * 100)
  return returns.reduce((acc, ret) => acc + ret, 0) / returns.length
})

const riskRewardRatio = computed(() => {
  if (strategyResults.value.length === 0) return 0
  const ratios = strategyResults.value.map(result => {
    const profit = result.takeProfitPrice - result.buyPrice
    const risk = result.buyPrice - result.stopLossPrice
    return profit / risk
  })
  return ratios.reduce((acc, ratio) => acc + ratio, 0) / ratios.length
})

const selectStrategy = (strategyId) => {
  selectedStrategy.value = strategyId
  const strategy = strategies.value.find(s => s.id === strategyId)
  if (strategy) {
    strategy.parameters.forEach(param => {
      strategyParameters[param.key] = param.value
    })
  }
}

const getCurrentStrategyParams = () => {
  const strategy = strategies.value.find(s => s.id === selectedStrategy.value)
  return strategy ? strategy.parameters : []
}

const runStrategy = async (strategyId) => {
  loading.value = true
  try {
    await new Promise(resolve => setTimeout(resolve, 2000))
    const mockResults = Array.from({ length: 8 }, (_, i) => ({
      id: i + 1,
      stockCode: `000${(i + 20).toString().padStart(3, '0')}`,
      stockName: `长线股票${i + 1}`,
      strategyName: strategies.value.find(s => s.id === strategyId)?.name || '',
      score: 0.70 + Math.random() * 0.30,
      buyPrice: 30 + Math.random() * 70,
      stopLossPrice: 0,
      takeProfitPrice: 0,
      logicDescription: '基本面优秀，估值合理，适合长期持有'
    }))
    mockResults.forEach(result => {
      result.stopLossPrice = result.buyPrice * 0.80
      result.takeProfitPrice = result.buyPrice * 1.50
    })
    strategyResults.value = mockResults
    ElMessage.success(`策略执行完成，生成 ${mockResults.length} 个信号`)
  } catch (error) {
    ElMessage.error('策略执行失败')
  } finally {
    loading.value = false
  }
}

const runAllStrategies = async () => {
  try {
    await ElMessageBox.confirm('确定要执行所有长线策略吗？', '提示', { confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning' })
    loading.value = true
    strategyResults.value = []
    for (const strategy of strategies.value) {
      await runStrategy(strategy.id)
    }
    ElMessage.success('所有策略执行完成')
  } catch (error) {
    if (error !== 'cancel') ElMessage.error('策略执行失败')
  } finally {
    loading.value = false
  }
}

const saveParameters = () => { ElMessage.success('参数保存成功') }
const resetParameters = () => { selectStrategy(selectedStrategy.value); ElMessage.info('参数已重置') }
const exportResults = () => { ElMessage.info('导出功能开发中...') }
const clearResults = () => { strategyResults.value = []; ElMessage.info('结果已清空') }
</script>

